```class Solution {
    public int[] pivotArray(int[] nums, int pivot) {
        int[] result = new int[nums.length];
        int left = 0, mid = 0, right = 0;
        for (int num : nums) {
            if (num < pivot) {
                result[left++] = num;
            } else if (num == pivot) {
                result[mid++] = num;
            } else {
                result[right++] = num;
            }
        }
        System.arraycopy(result, 0, nums, 0, left);
        System.arraycopy(result, left, nums, left, mid);
        System.arraycopy(result, left + mid, nums, left + mid, right);
        return nums;
    }
}```
